// src/components/TratamentoPaciente.js
import React from "react";
import OdontogramaSimples from "./OdontogramaSimples";

export default function TratamentoPaciente({ pacienteId }) {
  return (
    <div>
      <h2 className="text-xl font-bold mb-4">Tratamentos & Odontograma</h2>

      {/* Exemplo: mostrar o ID do paciente */}
      <p className="mb-6 text-gray-600">
        Paciente ID: <span className="font-mono">{pacienteId}</span>
      </p>

      {/* Odontograma SVG custom */}
      <div className="mb-10 mt-4 border rounded-lg p-6 bg-gray-50">
        <h3 className="font-semibold text-lg mb-3">Odontograma Interativo</h3>
        <OdontogramaSimples />
      </div>

      {/* Espaço reservado para histórico/lista de tratamentos */}
      <div className="mt-8">
        <h3 className="font-semibold text-lg mb-2">Histórico de Tratamentos</h3>
        <div className="text-gray-400 italic">
          [ Em breve: aqui será listada a tabela/linha do plano de tratamento do paciente. ]
        </div>
      </div>
    </div>
  );
}
